--- server.js ---
const path = require('path');
const express = require('express');

const app = express();

const publicDir = path.join(__dirname, 'public');

// Serve static assets from /public with basic caching rules
app.use(
  express.static(publicDir, {
    extensions: ['html'],
    maxAge: '1h',
    setHeaders: (res, filePath) => {
      if (path.extname(filePath) === '.html') {
        res.setHeader('Cache-Control', 'no-cache');
      }
    }
  })
);

// Health endpoint for uptime checks and tests
app.get('/health', (_req, res) => {
  res.json({ status: "ok" });
});

// Start server only when run directly (not when imported by tests)
if (require.main === module) {
  const PORT = process.env.PORT || 3000;
  app.listen(PORT, () => {
    // eslint-disable-next-line no-console
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

module.exports = app;


--- tests/index.test.js ---
const fs = require('fs');
const path = require('path');
const { JSDOM } = require('jsdom');

describe('index.html structure', () => {
  let document;

  beforeAll(() => {
    const html = fs.readFileSync(path.join(__dirname, '..', 'public', 'index.html'), 'utf8');
    const dom = new JSDOM(html);
    document = dom.window.document;
  });

  test('has hero title with id "hero-title"', () => {
    const titleEl = document.querySelector('#hero-title');
    expect(titleEl).not.toBeNull();
    expect(titleEl.textContent.trim()).toMatch(/Lab Technician/i);
  });

  test('links styles.css and app.js', () => {
    const stylesheet = document.querySelector('link[rel="stylesheet"][href="/styles.css"]');
    const script = document.querySelector('script[src="/app.js"]');
    expect(stylesheet).not.toBeNull();
    expect(script).not.toBeNull();
  });

  test('has services list and contact form fields', () => {
    const services = document.querySelector('#services .services-list');
    expect(services).not.toBeNull();
    const form = document.querySelector('#contact-form');
    expect(form).not.toBeNull();
    expect(document.querySelector('#name')).not.toBeNull();
    expect(document.querySelector('#email')).not.toBeNull();
    expect(document.querySelector('#message')).not.toBeNull();
  });
});


